  ('judicial-d35ec6db-moex-00017', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '「教唆犯須被教唆者著手實行犯罪行為，且具備違法性後，教唆者始成立教唆犯」，此段關於教唆犯之敘述， 是指何種共犯從屬形式？', '["限制從屬形式", "嚴格從屬形式", "最小限從屬形式", "最大限從屬形式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00018', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '依實務見解，關於教唆犯之敘述，下列何者錯誤？', '["教唆不特定人犯不特定之罪，亦成立教唆犯", "教唆犯須具教唆故意及教唆既遂故意", "教唆他人使之從事刑法未處罰之預備行為者，不成立教唆犯", "教唆犯之成立以教唆人與被教唆人有心理接觸為必要"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00019', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲、乙、丙相約共同竊取Ａ之財物。甲負責策劃犯罪計畫，並由乙和丙到場實施犯行。竊取過程中，乙負 責著手竊取財物，丙則於現場把風，下列敘述何者正確？', '["甲為竊盜罪之共謀共同正犯", "甲為竊盜罪之陰謀共同正犯", "乙為竊盜罪之間接正犯", "乙為竊盜罪之共謀共同正犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00020', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關刑法上易服社會勞動之敘述，下列何者正確？', '["除特殊情形外，罰金易服社會勞動係以6小時折算1日", "受1年以下有期徒刑之宣告，且符合易科罰金之規定者，得易服社會勞動", "執行完畢者，仍須執行其所受宣告之刑", "罰金易服勞役期間為1年以下之情形時，得以提供社會勞動半日折算半日，易服社會勞動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00021', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '下列行為，何者不屬刑法上的法定阻卻違法事由？', '["學生甲與其同學商議後，將其綑綁以便在同樂會上表演脫逃術", "司法警察乙為蒐集證據而持法院核發之搜索票進入民宅搜索", "熱心民眾丙短暫拘束現行犯之自由並即時通知警察到場處理", "休假的醫師丙在飛機上為瀕死的心臟病患急救而致其輕微挫傷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00022', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲開一槍，子彈穿透A之心臟後，致A死亡後，同一顆子彈竟又打傷A身後之B，下列敘述何者錯誤？', '["成立異種想像競合犯", "從法定刑較重罪名處斷", "不得科以較輕罪名所定最重本刑以下之刑", "屬裁判上一罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00023', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '依實務見解，關於競合敘述，下列何者錯誤？', '["接續犯係指述行為人在一個決意下，在同一時空密接之情形接續為同一性質之數行為而侵害同一法益者", "若行為人基於傷害犯意打人成傷之後，3個月後，又因其他原因殺害同一被害人，則傷害罪與殺人罪成 立想像競合", "集合犯係指立法者本就預定多數同種類之行為將反覆實行之犯罪類型", "一行為成立強制性交罪時，即不另論強制罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00024', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '依通說見解，下列各犯罪類型中，可成立間接正犯者為何？', '["刑法第237條之重婚罪", "刑法第122條之收受賄賂罪", "刑法第230條之血親性交罪", "刑法第168條之偽證罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00025', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關刑法對於假釋之規定內容，下列敘述何者正確？', '["於假釋中因故意更犯罪，受逾六月有期徒刑之宣告、且未受緩刑確定者，撤銷其假釋", "符合假釋條件者，由監獄報請法院許可假釋", "無期徒刑不得假釋", "假釋撤銷後，其出獄日數仍計入刑期內"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
